const data = $input.first().json;
const result = data.tasks?.[0]?.result?.[0];
const items = result?.items || [];

let compiled = [];

// ── 1. AI Overview ───────────────────────────────────────────
const aiOverview = items.find(item => item.type === 'ai_overview');

if (aiOverview) {
  compiled.push('=== AI OVERVIEW ===');
  (aiOverview.items || []).forEach(block => {
    if (block.text && block.type === 'ai_overview_element') {
      // Clean the text - remove image references and video descriptions
      const cleanText = block.text
        .replace(/\!\[.*?\]\(.*?\)/g, '')  // remove markdown images
        .replace(/\d+s\s+.*?YouTube.*?\d{4}/g, '')  // remove video snippets
        .trim();
      if (cleanText) {
        if (block.title) compiled.push(`${block.title}`);
        compiled.push(cleanText);
      }
    }
  });
}

// ── 2. Organic Results ───────────────────────────────────────
const organic = items.filter(item => item.type === 'organic');
if (organic.length > 0) {
  compiled.push('\n=== TOP SEARCH RESULTS ===');
  organic.slice(0, 5).forEach((r, i) => {
    compiled.push(`[${i + 1}] ${r.title || ''}`);
    compiled.push(`URL: ${r.url || ''}`);
    compiled.push(`${r.description || ''}`);
    compiled.push('');
  });
}

// ── 3. People Also Ask ───────────────────────────────────────
const paa = items.find(item => item.type === 'people_also_ask');
if (paa) {
  compiled.push('\n=== RELATED QUESTIONS ===');
  (paa.items || []).forEach(q => {
    const answer = q.expanded_element?.[0]?.description || '';
    if (answer) {
      compiled.push(`Q: ${q.title || ''}`);
      compiled.push(`A: ${answer}`);
      compiled.push('');
    }
  });
}

// ── 4. Related Searches ──────────────────────────────────────
const relatedSearches = items.find(item => item.type === 'related_searches');
if (relatedSearches?.items?.length > 0) {
  compiled.push('\n=== RELATED SEARCHES ===');
  compiled.push(relatedSearches.items.join(', '));
}

const finalText = compiled
  .filter(l => l !== null && l !== undefined)
  .join('\n')
  .trim();

return [{ json: { compiled_text: finalText || 'No data available' } }];

const raw = $input.first().json.output;

const cleaned = raw.split('\\n').join('');

return [{ json: { output: cleaned } }];
